<?php
namespace App\Http\Requests\Activation; use Illuminate\Foundation\Http\FormRequest;
class ActivateRequest extends FormRequest { public function authorize(): bool{return true;} public function rules(): array{return ['restaurant_code'=>['required','string','min:3','max:50','regex:/^[A-Za-z0-9_-]+$/'],'license_key'=>['required','string','min:10','max:120','regex:/^[A-Za-z0-9-]+$/'],'owner_email'=>['required','email:rfc,dns','max:191'],'owner_mobile'=>['required','regex:/^\+?[0-9]{8,20}$/'],'device'=>['required','array'],'device.uuid'=>['required','uuid'],'device.machine_fingerprint'=>['required','string','size:64'],'device.windows_username'=>['nullable','string','max:120'],'device.computer_name'=>['nullable','string','max:120'],'device.app_version'=>['required','string','max:30']];} public function messages(): array{return ['license_key.regex'=>'The license key format is invalid.'];}}
